from elasticsearch import Elasticsearch

es = Elasticsearch("http://localhost:9200")

resp = es.search(
    index="logs-*",
    query={
        "bool": {
            "must": [{"match": {"message": "OutOfMemoryError"}}],
            "filter": [
                {"term": {"level": "ERROR"}},
                {"range": {"@timestamp": {"gte": "now-7d/d"}}}
            ]
        }
    },
    aggs={
        "errors_per_day": {
            "date_histogram": {"field": "@timestamp", "calendar_interval": "day"}
        }
    },
    size=0
)
print(resp["aggregations"]["errors_per_day"]["buckets"])

-- Replaces: PUT /logs-index with mappings + refresh_interval
CREATE TABLE logs (
  id        BIGSERIAL PRIMARY KEY,
  payload   JSONB NOT NULL,
  embedding vector(384),
  created_at TIMESTAMPTZ DEFAULT now()
) PARTITION BY RANGE (created_at);

CREATE INDEX idx_logs_gin  ON logs USING GIN  (payload);
CREATE INDEX idx_logs_hnsw ON logs USING hnsw (embedding vector_cosine_ops);

-- Replaces: GET /logs-index/_search { query: match, knn }
SELECT id, payload
FROM   logs
WHERE  payload @@ to_tsquery('english', 'timeout & replica')
ORDER  BY embedding <=> '[0.12, 0.87, ...]'::vector
LIMIT  10;

-- Unlike ES bucket aggregations (computed at query time),
-- ClickHouse materializes aggregations at write time.

CREATE TABLE logs (
    ts DateTime,
    level String,
    service String
) ENGINE = MergeTree() ORDER BY (ts, level, service);

CREATE MATERIALIZED VIEW logs_hourly
ENGINE = SummingMergeTree() ORDER BY (hour, level, service)
AS SELECT toStartOfHour(ts) AS hour, level, service, count() AS hits
FROM logs GROUP BY hour, level, service;

-- Reads hit pre-aggregated rows instantly — no full scan
SELECT hour, level, sum(hits) FROM logs_hourly GROUP BY hour, level;

